const event = $input.first().json;
const data = event.data || event;
const comment = data.comment || event.comment || data;
const issue = data.issue || event.issue || comment.issue || {};
const user = data.user || event.user || data.actor || event.actor || comment.user || {};
const commentBody = comment.body || data.body || event.body || '';
const markerMatch = String(commentBody).match(/\[SV_APPROVAL\s+([^\]]+)\]/);
if (!markerMatch) return [{ json: { shouldQueue: false, reason: 'not an approval marker' } }];
const attrs = Object.fromEntries([...markerMatch[1].matchAll(/([A-Za-z_][A-Za-z0-9_]*)=([^\s]+)/g)].map((m) => [m[1], m[2]]));
if (attrs.decision !== 'approved' || !String(attrs.target || '').startsWith('proposal:') || !attrs.action_id) return [{ json: { shouldQueue: false, reason: 'not an approved proposal marker' } }];
const issueIdentifier = issue.identifier || data.issueIdentifier || event.issueIdentifier || issue.key;
if (!issueIdentifier) throw new Error('Linear issue identifier missing');
const commentId = comment.id || data.id || event.id || '';
return [{ json: { shouldQueue: true, row: { event_id: `evt_linear_${issueIdentifier}_${attrs.action_id}`.replace(/[^A-Za-z0-9_-]/g, '_'), created_at: new Date().toISOString(), updated_at: new Date().toISOString(), source: 'linear', source_event_id: String(event.webhookTimestamp || event.createdAt || event.updatedAt || event.id || commentId), linear_issue_id: issue.id || data.issueId || event.issueId || '', linear_issue_identifier: issueIdentifier, linear_comment_id: commentId, tenant_key: '', tenant_project_id: '', type: 'linear_marker_detected', status: 'queued', priority: 2, actor_kind: 'linear_user', actor_id: user.id || data.userId || event.userId || '', dedupe_key: `linear:${issueIdentifier}:${attrs.action_id}`, payload_json: JSON.stringify({ action_id: attrs.action_id, marker_type: 'SV_APPROVAL', target: attrs.target, decision: attrs.decision }), attempts: 0, claimed_by: '', claimed_at: '', lease_until: '', last_error: '', result_linear_comment_id: '', processed_at: '' } } }];
